{
  "name": "FrameGrabber Pro",
  "description": "A professional dark-themed tool to extract high-quality preview images from videos and export them as a ZIP archive."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Screenshot {
  id: string;
  blob: Blob;
  url: string;
  timestamp: number;
  fileName: string;
}

export interface VideoMetadata {
  duration: number;
  width: number;
  height: number;
  filename: string;
}

export enum ProcessingStatus {
  IDLE = 'IDLE',
  LOADING_VIDEO = 'LOADING_VIDEO',
  EXTRACTING = 'EXTRACTING',
  ZIPPING = 'ZIPPING',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR'
}

import { Screenshot, VideoMetadata } from '../types';

export const loadVideo = (file: File): Promise<{ video: HTMLVideoElement; metadata: VideoMetadata }> => {
  return new Promise((resolve, reject) => {
    const video = document.createElement('video');
    video.preload = 'metadata';
    video.muted = true;
    video.playsInline = true;

    const objectUrl = URL.createObjectURL(file);
    video.src = objectUrl;

    video.onloadedmetadata = () => {
      resolve({
        video,
        metadata: {
          duration: video.duration,
          width: video.videoWidth,
          height: video.videoHeight,
          filename: file.name
        }
      });
    };

    video.onerror = () => {
      URL.revokeObjectURL(objectUrl);
      reject(new Error('Failed to load video file.'));
    };
  });
};

export const extractFrames = async (
  video: HTMLVideoElement,
  count: number,
  onProgress: (progress: number) => void
): Promise<Screenshot[]> => {
  const screenshots: Screenshot[] = [];
  const duration = video.duration;

  // Create an off-screen canvas
  const canvas = document.createElement('canvas');
  canvas.width = video.videoWidth;
  canvas.height = video.videoHeight;
  const ctx = canvas.getContext('2d');

  if (!ctx) {
    throw new Error('Could not create 2D context');
  }

  // Calculate timestamps (avoiding exact 0 and exact end to ensure valid frames)
  // Example: 2 mins (120s), 4 frames -> ~30s intervals
  const step = duration / (count + 1);
  const timestamps = Array.from({ length: count }, (_, i) => step * (i + 1));

  for (let i = 0; i < timestamps.length; i++) {
    const time = timestamps[i];

    // Seek
    video.currentTime = time;
    await new Promise<void>((resolve) => {
      const onSeeked = () => {
        video.removeEventListener('seeked', onSeeked);
        resolve();
      };
      video.addEventListener('seeked', onSeeked);
    });

    // Draw
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

    // Convert to Blob
    const blob = await new Promise<Blob | null>((resolve) => 
      canvas.toBlob(resolve, 'image/jpeg', 0.85)
    );

    if (blob) {
      const url = URL.createObjectURL(blob);
      const timestampStr = new Date(time * 1000).toISOString().substr(11, 8).replace(/:/g, '-');

      screenshots.push({
        id: crypto.randomUUID(),
        blob,
        url,
        timestamp: time,
        fileName: `frame_${timestampStr}.jpg`
      });
    }

    // Update progress (0 to 100)
    onProgress(Math.round(((i + 1) / count) * 100));
  }

  // Cleanup video src is handled by the caller or global cleanup
  return screenshots;
};

export const formatTime = (seconds: number): string => {
  const date = new Date(0);
  date.setSeconds(seconds);
  return date.toISOString().substr(11, 8);
};

import React from 'react';

interface SettingsControlsProps {
  count: number;
  setCount: (n: number) => void;
  disabled: boolean;
}

const SettingsControls: React.FC<SettingsControlsProps> = ({ count, setCount, disabled }) => {
  return (
    <div className="bg-gray-900 rounded-xl p-6 border border-gray-800 shadow-lg mb-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h3 className="text-lg font-semibold text-white mb-1">Extraction Settings</h3>
          <p className="text-gray-400 text-sm">Choose how many preview images to generate from the video.</p>
        </div>

        <div className="flex items-center gap-6 flex-1 max-w-md">
          <div className="flex-1">
            <input
              type="range"
              min="1"
              max="50"
              value={count}
              onChange={(e) => setCount(parseInt(e.target.value))}
              disabled={disabled}
              className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-indigo-500 disabled:opacity-50"
            />
            <div className="flex justify-between text-xs text-gray-500 mt-2">
              <span>1 frame</span>
              <span>25 frames</span>
              <span>50 frames</span>
            </div>
          </div>

          <div className="bg-gray-800 border border-gray-700 rounded-lg px-4 py-2 flex flex-col items-center min-w-[80px]">
            <span className="text-2xl font-bold text-indigo-400">{count}</span>
            <span className="text-[10px] text-gray-500 uppercase tracking-wider">Images</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SettingsControls;

import React, { useRef } from 'react';

interface VideoUploaderProps {
  onFileSelect: (file: File) => void;
  disabled: boolean;
}

const VideoUploader: React.FC<VideoUploaderProps> = ({ onFileSelect, disabled }) => {
  const inputRef = useRef<HTMLInputElement>(null);

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (disabled) return;

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      validateAndPass(e.dataTransfer.files[0]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      validateAndPass(e.target.files[0]);
    }
  };

  const validateAndPass = (file: File) => {
    if (file.type.startsWith('video/')) {
      onFileSelect(file);
    } else {
      alert('Please upload a valid video file.');
    }
  };

  return (
    <div 
      onClick={() => !disabled && inputRef.current?.click()}
      onDragOver={handleDragOver}
      onDrop={handleDrop}
      className={`
        relative group cursor-pointer 
        border-2 border-dashed rounded-2xl p-10 
        transition-all duration-300 ease-in-out
        flex flex-col items-center justify-center
        text-center
        ${disabled ? 'opacity-50 cursor-not-allowed border-gray-700 bg-gray-900' : 'border-gray-700 hover:border-indigo-500 hover:bg-gray-900/50 bg-gray-900'}
      `}
    >
      <input 
        type="file" 
        ref={inputRef} 
        onChange={handleChange} 
        accept="video/*" 
        className="hidden" 
        disabled={disabled}
      />

      <div className={`
        w-16 h-16 rounded-full bg-gray-800 flex items-center justify-center mb-4
        group-hover:scale-110 transition-transform duration-300
        ${!disabled && 'group-hover:bg-indigo-500/20 group-hover:text-indigo-400'}
      `}>
        <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-gray-400 group-hover:text-indigo-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
        </svg>
      </div>

      <h3 className="text-xl font-medium text-white mb-2">
        {disabled ? 'Processing Video...' : 'Upload Video File'}
      </h3>
      <p className="text-gray-400 text-sm max-w-sm">
        Drag and drop your video here, or click to browse. 
        <br/><span className="text-gray-500 text-xs mt-1 block">Supports MP4, WebM, MOV (approx 2-4 mins recommended)</span>
      </p>
    </div>
  );
};

export default VideoUploader;

import React from 'react';
import { Screenshot } from '../types';
import { formatTime } from '../utils/videoUtils';

interface GalleryProps {
  screenshots: Screenshot[];
  onRemove: (id: string) => void;
}

const Gallery: React.FC<GalleryProps> = ({ screenshots, onRemove }) => {
  if (screenshots.length === 0) return null;

  return (
    <div className="mt-12">
      <div className="flex items-center justify-between mb-6">
        <h3 className="text-xl font-bold text-white">Extracted Frames <span className="text-indigo-500">({screenshots.length})</span></h3>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
        {screenshots.map((shot) => (
          <div key={shot.id} className="group relative bg-gray-800 rounded-lg overflow-hidden border border-gray-700 hover:border-indigo-500 transition-colors">
            <div className="aspect-video w-full overflow-hidden bg-gray-900 relative">
               <img 
                 src={shot.url} 
                 alt={`Frame at ${shot.timestamp}`} 
                 className="w-full h-full object-cover transform group-hover:scale-105 transition-transform duration-500"
               />
               <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                 <button 
                   onClick={() => window.open(shot.url, '_blank')}
                   className="p-2 bg-gray-700 rounded-full hover:bg-indigo-600 text-white transition-colors"
                   title="View Full Size"
                 >
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                     <path d="M10 12a2 2 0 100-4 2 2 0 000 4z" />
                     <path fillRule="evenodd" d="M.458 10C1.732 5.943 5.522 3 10 3s8.268 2.943 9.542 7c-1.274 4.057-5.064 7-9.542 7S1.732 14.057.458 10zM14 10a4 4 0 11-8 0 4 4 0 018 0z" clipRule="evenodd" />
                   </svg>
                 </button>
                 <button 
                   onClick={() => onRemove(shot.id)}
                   className="p-2 bg-gray-700 rounded-full hover:bg-red-500 text-white transition-colors"
                   title="Remove Frame"
                 >
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                     <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                   </svg>
                 </button>
               </div>
            </div>
            <div className="p-3">
              <p className="text-xs font-mono text-indigo-400 bg-indigo-500/10 inline-block px-2 py-1 rounded">
                {formatTime(shot.timestamp)}
              </p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Gallery;

import React, { useState, useEffect, useCallback } from 'react';
import JSZip from 'jszip';
import { saveAs } from 'file-saver';
import { ProcessingStatus, Screenshot, VideoMetadata } from './types';
import { extractFrames, loadVideo } from './utils/videoUtils';
import VideoUploader from './components/VideoUploader';
import SettingsControls from './components/SettingsControls';
import Gallery from './components/Gallery';

function App() {
  const [file, setFile] = useState<File | null>(null);
  const [metadata, setMetadata] = useState<VideoMetadata | null>(null);
  const [status, setStatus] = useState<ProcessingStatus>(ProcessingStatus.IDLE);
  const [progress, setProgress] = useState<number>(0);
  const [screenshots, setScreenshots] = useState<Screenshot[]>([]);
  const [count, setCount] = useState<number>(12);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Clean up object URLs when components unmount or screenshots change
  useEffect(() => {
    return () => {
      screenshots.forEach(s => URL.revokeObjectURL(s.url));
    };
  }, [screenshots]);

  const handleFileSelect = async (selectedFile: File) => {
    setFile(selectedFile);
    setStatus(ProcessingStatus.LOADING_VIDEO);
    setErrorMsg(null);
    setScreenshots([]);

    try {
      const { metadata } = await loadVideo(selectedFile);
      setMetadata(metadata);
      setStatus(ProcessingStatus.IDLE);
    } catch (err) {
      console.error(err);
      setErrorMsg('Failed to load video. Please try another file.');
      setStatus(ProcessingStatus.ERROR);
    }
  };

  const handleStartExtraction = async () => {
    if (!file) return;

    setStatus(ProcessingStatus.EXTRACTING);
    setProgress(0);
    setScreenshots([]);
    setErrorMsg(null);

    try {
      // Re-load video element specifically for extraction to ensure fresh state
      const { video } = await loadVideo(file);

      const frames = await extractFrames(video, count, (pct) => {
        setProgress(pct);
      });

      setScreenshots(frames);
      setStatus(ProcessingStatus.COMPLETED);

      // Cleanup the video element source
      URL.revokeObjectURL(video.src);
      video.remove();

    } catch (err) {
      console.error(err);
      setErrorMsg('Error during frame extraction.');
      setStatus(ProcessingStatus.ERROR);
    }
  };

  const handleDownloadZip = async () => {
    if (screenshots.length === 0) return;

    setStatus(ProcessingStatus.ZIPPING);
    const zip = new JSZip();
    const folder = zip.folder("screenshots");

    if (folder) {
      screenshots.forEach((shot) => {
        folder.file(shot.fileName, shot.blob);
      });

      try {
        const content = await zip.generateAsync({ type: "blob" });
        const zipName = metadata ? `${metadata.filename.split('.')[0]}_preview.zip` : 'video_previews.zip';
        saveAs(content, zipName);
        setStatus(ProcessingStatus.COMPLETED);
      } catch (err) {
        console.error(err);
        setErrorMsg('Failed to create zip file.');
        setStatus(ProcessingStatus.ERROR);
      }
    }
  };

  const handleRemoveScreenshot = useCallback((id: string) => {
    setScreenshots(prev => prev.filter(s => s.id !== id));
  }, []);

  const handleReset = () => {
    setFile(null);
    setMetadata(null);
    setScreenshots([]);
    setStatus(ProcessingStatus.IDLE);
    setErrorMsg(null);
    setProgress(0);
  };

  const isProcessing = status === ProcessingStatus.EXTRACTING || status === ProcessingStatus.ZIPPING || status === ProcessingStatus.LOADING_VIDEO;

  return (
    <div className="min-h-screen bg-[#030712] text-gray-100 font-sans selection:bg-indigo-500/30 selection:text-indigo-200">

      {/* Navbar */}
      <nav className="border-b border-gray-800 bg-[#030712]/80 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center shadow-lg shadow-indigo-500/20">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-white" viewBox="0 0 20 20" fill="currentColor">
                  <path d="M4 3a2 2 0 100 4h12a2 2 0 100-4H4z" />
                  <path fillRule="evenodd" d="M3 8h14v7a2 2 0 01-2 2H5a2 2 0 01-2-2V8zm5 3a1 1 0 011-1h2a1 1 0 110 2H9a1 1 0 01-1-1z" clipRule="evenodd" />
                </svg>
              </div>
              <span className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-gray-400">
                FrameGrabber Pro
              </span>
            </div>
            <div>
              <a href="#" className="text-sm text-gray-400 hover:text-white transition-colors">Help</a>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">

        {/* Header Section */}
        <div className="mb-10 text-center">
          <h1 className="text-4xl md:text-5xl font-extrabold text-white mb-4 tracking-tight">
            Extract Highlights from <span className="text-indigo-400">Videos</span>
          </h1>
          <p className="text-lg text-gray-400 max-w-2xl mx-auto">
            Upload a video file, select how many screenshots you need, and download them instantly as a ZIP archive.
            Perfect for thumbnails, previews, and datasets.
          </p>
        </div>

        {/* Error Banner */}
        {errorMsg && (
          <div className="bg-red-900/20 border border-red-800 text-red-200 px-4 py-3 rounded-lg mb-8 flex items-center gap-3">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
            </svg>
            {errorMsg}
          </div>
        )}

        {/* Main Interface */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Upload & Settings */}
          <div className="lg:col-span-5 space-y-6">

            {!file ? (
              <VideoUploader onFileSelect={handleFileSelect} disabled={false} />
            ) : (
              <div className="bg-gray-900 rounded-xl p-6 border border-gray-800 shadow-lg">
                <div className="flex items-start justify-between mb-4">
                  <div className="flex items-center gap-3 overflow-hidden">
                    <div className="bg-indigo-900/50 p-3 rounded-lg">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-indigo-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" />
                      </svg>
                    </div>
                    <div className="min-w-0">
                      <h3 className="font-semibold text-white truncate">{file.name}</h3>
                      <p className="text-sm text-gray-400">
                        {(file.size / (1024 * 1024)).toFixed(2)} MB • {metadata ? `${Math.floor(metadata.duration / 60)}m ${Math.floor(metadata.duration % 60)}s` : 'Loading info...'}
                      </p>
                    </div>
                  </div>
                  <button 
                    onClick={handleReset}
                    className="text-gray-500 hover:text-red-400 transition-colors p-1"
                    title="Remove Video"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                    </svg>
                  </button>
                </div>

                <div className="w-full bg-gray-800 rounded-full h-1.5 mb-6 overflow-hidden">
                  <div className="bg-indigo-500 h-1.5 rounded-full" style={{width: '100%'}}></div>
                </div>

                <button
                  onClick={handleStartExtraction}
                  disabled={isProcessing}
                  className={`
                    w-full py-4 rounded-xl font-bold text-lg shadow-lg shadow-indigo-900/20
                    flex items-center justify-center gap-2
                    transition-all duration-300 transform hover:-translate-y-0.5 active:translate-y-0
                    ${isProcessing 
                      ? 'bg-gray-800 text-gray-500 cursor-wait' 
                      : 'bg-gradient-to-r from-indigo-600 to-violet-600 hover:from-indigo-500 hover:to-violet-500 text-white'
                    }
                  `}
                >
                  {isProcessing ? (
                     <>
                       <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                         <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                         <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                       </svg>
                       {status === ProcessingStatus.EXTRACTING ? `Extracting ${progress}%` : 'Processing...'}
                     </>
                  ) : (
                    <>
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                      </svg>
                      Generate Previews
                    </>
                  )}
                </button>
              </div>
            )}

            <SettingsControls 
              count={count} 
              setCount={setCount} 
              disabled={isProcessing || !file} 
            />

            {screenshots.length > 0 && (
              <div className="bg-gray-900 rounded-xl p-6 border border-gray-800 shadow-lg animate-fade-in">
                 <div className="flex items-center justify-between">
                    <div>
                      <h3 className="text-white font-semibold">Ready to Download</h3>
                      <p className="text-gray-400 text-sm">{screenshots.length} images prepared</p>
                    </div>
                    <button
                      onClick={handleDownloadZip}
                      disabled={status === ProcessingStatus.ZIPPING}
                      className="bg-gray-800 hover:bg-gray-700 text-indigo-400 font-medium px-4 py-2 rounded-lg border border-gray-700 hover:border-indigo-500/50 transition-all flex items-center gap-2"
                    >
                      {status === ProcessingStatus.ZIPPING ? (
                        <span className="animate-pulse">Zipping...</span>
                      ) : (
                        <>
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                            <path fillRule="evenodd" d="M3 17a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1zm3.293-7.707a1 1 0 011.414 0L9 10.586V3a1 1 0 112 0v7.586l1.293-1.293a1 1 0 111.414 1.414l-3 3a1 1 0 01-1.414 0l-3-3a1 1 0 010-1.414z" clipRule="evenodd" />
                          </svg>
                          Download ZIP
                        </>
                      )}
                    </button>
                 </div>
              </div>
            )}

          </div>

          {/* Right Column: Preview Gallery */}
          <div className="lg:col-span-7">
            {screenshots.length > 0 ? (
               <Gallery screenshots={screenshots} onRemove={handleRemoveScreenshot} />
            ) : (
              <div className="h-full min-h-[400px] border-2 border-dashed border-gray-800 rounded-2xl flex flex-col items-center justify-center text-gray-600 bg-gray-900/20">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mb-4 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                </svg>
                <p>No preview images generated yet.</p>
                <p className="text-sm mt-2">Upload a video and click Generate.</p>
              </div>
            )}
          </div>
