             <Gallery screenshots={screenshots} onRemove={handleRemoveScreenshot} />
          ) : (
            <div className="h-full min-h-[400px] flex flex-col items-center justify-center border-2 border-dashed border-gray-800/50 rounded-2xl text-gray-600 bg-gray-900/10">
              <div className="p-6 rounded-full bg-gray-900/50 mb-4">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 opacity-30" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                </svg>
              </div>
              <p className="text-lg font-medium text-gray-500">No images extracted yet</p>
              <p className="text-sm mt-1 text-gray-600">Upload a video in the sidebar to get started</p>
            </div>
          )}
        </main>

      </div>
    </div>
  );
}

