import React, { useState, useEffect, useCallback } from 'react';
import JSZip from 'jszip';
import saveAs from 'file-saver';
import { ProcessingStatus, Screenshot, VideoMetadata } from './types';
import { extractFrames, loadVideo } from './utils/videoUtils';
import VideoUploader from './components/VideoUploader';
import SettingsControls from './components/SettingsControls';
import Gallery from './components/Gallery';

function App() {
  const [file, setFile] = useState<File | null>(null);
  const [metadata, setMetadata] = useState<VideoMetadata | null>(null);
  const [status, setStatus] = useState<ProcessingStatus>(ProcessingStatus.IDLE);
  const [progress, setProgress] = useState<number>(0);
  const [screenshots, setScreenshots] = useState<Screenshot[]>([]);
  const [count, setCount] = useState<number>(12);
  const [randomize, setRandomize] = useState<boolean>(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Clean up object URLs when components unmount or screenshots change
  useEffect(() => {
    return () => {
      screenshots.forEach(s => URL.revokeObjectURL(s.url));
    };
  }, [screenshots]);

  const handleFileSelect = async (selectedFile: File) => {
    setFile(selectedFile);
    setStatus(ProcessingStatus.LOADING_VIDEO);
    setErrorMsg(null);
    setScreenshots([]);

    try {
      const { metadata } = await loadVideo(selectedFile);
      setMetadata(metadata);
      setStatus(ProcessingStatus.IDLE);
    } catch (err) {
      console.error(err);
      setErrorMsg('Failed to load video. Please try another file.');
      setStatus(ProcessingStatus.ERROR);
    }
  };

  const handleStartExtraction = async () => {
    if (!file) return;

    setStatus(ProcessingStatus.EXTRACTING);
    setProgress(0);
    setScreenshots([]);
    setErrorMsg(null);

    try {
      // Re-load video element specifically for extraction to ensure fresh state
      const { video } = await loadVideo(file);

      const frames = await extractFrames(video, count, randomize, (pct) => {
        setProgress(pct);
      });

      setScreenshots(frames);
      setStatus(ProcessingStatus.COMPLETED);

      // Cleanup the video element source
      URL.revokeObjectURL(video.src);
      video.remove();

    } catch (err) {
      console.error(err);
      setErrorMsg('Error during frame extraction.');
      setStatus(ProcessingStatus.ERROR);
    }
  };

  const handleDownloadZip = async () => {
    if (screenshots.length === 0) return;

    setStatus(ProcessingStatus.ZIPPING);
    const zip = new JSZip();
    const folder = zip.folder("screenshots");

    if (folder) {
      screenshots.forEach((shot) => {
        folder.file(shot.fileName, shot.blob);
      });

      try {
        const content = await zip.generateAsync({ type: "blob" });
        const zipName = metadata ? `${metadata.filename.split('.')[0]}_preview.zip` : 'frame_scout_previews.zip';
        saveAs(content, zipName);
        setStatus(ProcessingStatus.COMPLETED);
      } catch (err) {
        console.error(err);
        setErrorMsg('Failed to create zip file.');
        setStatus(ProcessingStatus.ERROR);
      }
    }
  };

  const handleRemoveScreenshot = useCallback((id: string) => {
    setScreenshots(prev => prev.filter(s => s.id !== id));
  }, []);

  const handleReset = () => {
    setFile(null);
    setMetadata(null);
    setScreenshots([]);
    setStatus(ProcessingStatus.IDLE);
    setErrorMsg(null);
    setProgress(0);
  };

  const isProcessing = status === ProcessingStatus.EXTRACTING || status === ProcessingStatus.ZIPPING || status === ProcessingStatus.LOADING_VIDEO;

  return (
    <div className="h-screen flex flex-col bg-[#030712] text-gray-100 font-sans selection:bg-indigo-500/30 selection:text-indigo-200 overflow-hidden">

      {/* Navbar */}
      <nav className="flex-shrink-0 border-b border-gray-800 bg-[#030712] z-50">
        <div className="max-w-full mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center shadow-lg shadow-indigo-500/20">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-white" viewBox="0 0 20 20" fill="currentColor">
                  <path d="M4 3a2 2 0 100 4h12a2 2 0 100-4H4z" />
                  <path fillRule="evenodd" d="M3 8h14v7a2 2 0 01-2 2H5a2 2 0 01-2-2V8zm5 3a1 1 0 011-1h2a1 1 0 110 2H9a1 1 0 01-1-1z" clipRule="evenodd" />
                </svg>
              </div>
              <span className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-gray-400">
                FrameScout
              </span>
            </div>
            <div>
              <a href="#" className="text-sm text-gray-400 hover:text-white transition-colors">Help</a>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content Area - Split View */}
      <div className="flex-1 flex flex-col lg:flex-row overflow-hidden">

        {/* LEFT PANEL: Settings & Controls (Scrollable independently) */}
        <aside className="w-full lg:w-[480px] flex-shrink-0 overflow-y-auto border-b lg:border-b-0 lg:border-r border-gray-800 bg-[#030712] p-6 lg:p-8 z-10 custom-scrollbar">

          <div className="mb-8">
            <h1 className="text-3xl font-extrabold text-white mb-2 tracking-tight">
              Extract <span className="text-indigo-400">Highlights</span>
            </h1>
            <p className="text-gray-400 text-sm leading-relaxed">
              Upload a video, choose frame count, and export high-quality previews instantly.
            </p>
          </div>

          {/* Error Banner */}
          {errorMsg && (
            <div className="bg-red-900/20 border border-red-800 text-red-200 px-4 py-3 rounded-lg mb-6 flex items-center gap-3 text-sm">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 flex-shrink-0" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
              </svg>
              {errorMsg}
            </div>
          )}

          <div className="space-y-6">
            {!file ? (
              <VideoUploader onFileSelect={handleFileSelect} disabled={false} />
            ) : (
              <div className="bg-gray-900 rounded-xl p-5 border border-gray-800 shadow-lg">
                <div className="flex items-start justify-between mb-4">
                  <div className="flex items-center gap-3 overflow-hidden">
                    <div className="bg-indigo-900/50 p-2.5 rounded-lg flex-shrink-0">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-indigo-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" />
                      </svg>
                    </div>
                    <div className="min-w-0">
                      <h3 className="font-semibold text-white truncate text-sm">{file.name}</h3>
                      <p className="text-xs text-gray-400">
                        {(file.size / (1024 * 1024)).toFixed(2)} MB • {metadata ? `${Math.floor(metadata.duration / 60)}m ${Math.floor(metadata.duration % 60)}s` : 'Loading...'}
                      </p>
                    </div>
                  </div>
                  <button 
                    onClick={handleReset}
                    className="text-gray-500 hover:text-red-400 transition-colors p-1"
                    title="Remove Video"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                    </svg>
                  </button>
                </div>

                <div className="w-full bg-gray-800 rounded-full h-1.5 mb-6 overflow-hidden">
                  <div className="bg-indigo-500 h-1.5 rounded-full" style={{width: '100%'}}></div>
                </div>

                <button
                  onClick={handleStartExtraction}
                  disabled={isProcessing}
                  className={`
                    w-full py-3.5 rounded-xl font-bold text-base shadow-lg shadow-indigo-900/20
                    flex items-center justify-center gap-2
                    transition-all duration-300 transform hover:-translate-y-0.5 active:translate-y-0
                    ${isProcessing 
                      ? 'bg-gray-800 text-gray-500 cursor-wait' 
                      : 'bg-gradient-to-r from-indigo-600 to-violet-600 hover:from-indigo-500 hover:to-violet-500 text-white'
                    }
                  `}
                >
                  {isProcessing ? (
                     <>
                       <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                         <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                         <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                       </svg>
                       {status === ProcessingStatus.EXTRACTING ? `Extracting ${progress}%` : 'Processing...'}
                     </>
                  ) : (
                    <>
                      {screenshots.length > 0 ? (
                        <>
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                            <path fillRule="evenodd" d="M4 2a1 1 0 011 1v2.101a1 1 0 01-1.5.866l-2.5-1.5a1 1 0 010-1.732l2.5-1.5A1 1 0 014 2z" clipRule="evenodd" />
                            <path fillRule="evenodd" d="M11.5 5.5a1 1 0 011-1h.01a1 1 0 110 2h-.01a1 1 0 01-1-1z" clipRule="evenodd" />
                            <path d="M9 13a3 3 0 100-6 3 3 0 000 6z" />
                          </svg>
                          Regenerate Previews
                        </>
                      ) : (
                        <>
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                          </svg>
                          Generate Previews
                        </>
                      )}
                    </>
                  )}
                </button>
              </div>
            )}

            <SettingsControls 
              count={count} 
              setCount={setCount} 
              randomize={randomize}
              setRandomize={setRandomize}
              disabled={isProcessing || !file} 
            />

            {screenshots.length > 0 && (
              <div className="bg-gray-900 rounded-xl p-5 border border-gray-800 shadow-lg animate-fade-in">
                 <div className="flex items-center justify-between">
                    <div>
                      <h3 className="text-white font-semibold text-sm">Download All</h3>
