        </aside>

        {/* RIGHT PANEL: Gallery (Primary Scroll) */}
        <main className="flex-1 overflow-y-auto bg-[#030304] p-6 lg:p-8 custom-scrollbar relative">
          <div className="max-w-7xl mx-auto h-full">
